#include <stdlib.h>
int main(){
    int N; 
    while (scanf("%d", &N)==1){
        if (N!=2){
            printf("-1\n");
            continue;
        }
        // grid for N=2
        printf("0 1\n");
        printf("1 0\n");
        // path string of length 4 (2*2)
        printf("RDLU\n");
    }
    return 0;
}

